"use client";

import { IconMaximize, IconMinimize } from "@tabler/icons-react";

interface YtcnFullscreenProps {
  /** Whether the player is currently in fullscreen mode */
  isFullscreen: boolean;
  /** Toggle fullscreen on/off */
  onToggle: () => void;
}

/**
 * YtcnFullscreen — Fullscreen toggle button.
 *
 * Switches icon between maximize and minimize based on current state.
 */
export function YtcnFullscreen({ isFullscreen, onToggle }: YtcnFullscreenProps) {
  return (
    <button
      onClick={(e) => {
        e.stopPropagation();
        onToggle();
      }}
      className="flex items-center justify-center rounded-sm p-1.5 text-white transition-colors hover:bg-white/10"
      aria-label={isFullscreen ? "Exit fullscreen" : "Fullscreen"}
    >
      {isFullscreen ? (
        <IconMinimize className="size-5" />
      ) : (
        <IconMaximize className="size-5" />
      )}
    </button>
  );
}
